// Edge Gateway entrypoint — a vanilla Cloudflare Worker that fronts the
// ItemsStore Durable Object. It handles CORS, security headers, per-IP rate
// limiting (in the DO), and real edge caching for GET reads via the Cache API.

export { ItemsStore } from "./items-store";

type Env = {
  DO: DurableObjectNamespace;
  /** Default upstream origin for the reverse proxy, e.g. "https://example.com". */
  PROXY_TARGET?: string;
  /** Cloudflare Global API Key (used with CF_API_EMAIL). */
  CF_API_KEY?: string;
  /** Cloudflare account email that owns CF_API_KEY. */
  CF_API_EMAIL?: string;
  /** Optional scoped API token (Bearer) used instead of the global key. */
  CF_API_TOKEN?: string;
  /** When "true", the gateway inspects proxied payloads for intercept captures. */
  INTERCEPT_LAB_MODE?: string;
  /** Comma-separated upstream hostname allowlist for intercept captures. */
  INTERCEPT_ALLOWLIST?: string;
  /** TTL in seconds for intercept captures (default: 600 = 10 min). */
  INTERCEPT_TTL_SECONDS?: string;
};

const CF_API = "https://api.cloudflare.com/client/v4";

/**
 * Build Cloudflare API auth headers from the configured credentials. A scoped
 * Bearer token wins if present, otherwise the global key + account email is
 * used. Returns null when nothing is configured.
 */
function cfAuthHeaders(env: Env): Record<string, string> | null {
  if (env.CF_API_TOKEN) {
    return { Authorization: `Bearer ${env.CF_API_TOKEN}` };
  }
  if (env.CF_API_KEY && env.CF_API_EMAIL) {
    return { "X-Auth-Email": env.CF_API_EMAIL, "X-Auth-Key": env.CF_API_KEY };
  }
  return null;
}

/**
 * Build Cloudflare API auth headers, falling back to DO-stored config if env
 * vars are not set. This allows runtime credential updates via the Settings UI.
 */
async function loadCfAuth(
  env: Env,
): Promise<Record<string, string> | null> {
  // Env vars take priority
  const fromEnv = cfAuthHeaders(env);
  if (fromEnv) return fromEnv;

  // Fall back to DO-stored config
  const config = await readConfigFromDO(env, "cf.");
  const token = config["cf.api_token"] ?? "";
  if (token) {
    return { Authorization: `Bearer ${token}` };
  }
  const key = config["cf.api_key"] ?? "";
  const email = config["cf.api_email"] ?? "";
  if (key && email) {
    return { "X-Auth-Email": email, "X-Auth-Key": key };
  }
  return null;
}

/** Read config entries from the DO by prefix. */
async function readConfigFromDO(
  env: Env,
  prefix: string,
): Promise<Record<string, string>> {
  const req = new Request(
    `https://do/__config?prefix=${encodeURIComponent(prefix)}`,
  );
  req.headers.set("X-Rork-DO-Class", "ItemsStore");
  req.headers.set("X-Rork-DO-Id", STORE_ID);
  const res = await fetchDO(env, req);
  if (!res.ok) return {};
  const json = (await res.json()) as { data?: Record<string, string> };
  return json.data ?? {};
}

/** Write config entries to the DO (upsert). */
async function writeConfigToDO(
  env: Env,
  entries: Record<string, string | null>,
): Promise<void> {
  const req = new Request("https://do/__config", {
    method: "PUT",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(entries),
  });
  req.headers.set("X-Rork-DO-Class", "ItemsStore");
  req.headers.set("X-Rork-DO-Id", STORE_ID);
  await fetchDO(env, req);
}

function fetchDO(env: Env, req: Request): Promise<Response> {
  const doId = env.DO.idFromName(STORE_ID);
  return env.DO.get(doId).fetch(req);
}

type CfApiResponse<T> = {
  success: boolean;
  result?: T;
  errors?: { code: number; message: string }[];
};

type CfZone = { id: string; name: string; status: string };

/** List the purchased domains (zones) in the configured Cloudflare account. */
async function listZones(env: Env): Promise<Response> {
  const auth = await loadCfAuth(env);
  if (!auth) {
    return decorate(
      Response.json(
        { success: false, configured: false, error: "Cloudflare credentials not configured" },
        { status: 200 },
      ),
    );
  }
  try {
    const res = await fetch(`${CF_API}/zones?per_page=50&status=active`, {
      headers: auth,
    });
    const json = (await res.json()) as CfApiResponse<CfZone[]>;
    if (!json.success) {
      return decorate(
        Response.json(
          {
            success: false,
            configured: true,
            error: json.errors?.[0]?.message ?? "Cloudflare API rejected the request",
          },
          { status: 502 },
        ),
      );
    }
    const zones = (json.result ?? []).map((z) => ({
      id: z.id,
      name: z.name,
      status: z.status,
    }));
    return decorate(Response.json({ success: true, configured: true, data: zones }));
  } catch {
    return decorate(
      Response.json(
        { success: false, configured: true, error: "could not reach the Cloudflare API" },
        { status: 502 },
      ),
    );
  }
}

type CfAccount = { id: string; name: string };
type CfWorkerScript = { id: string; modified_on?: string };

/**
 * List the Workers in the configured Cloudflare account, including their
 * workers.dev hostnames. Used by the Settings UI to populate the gateway host
 * dropdown.
 */
async function listWorkers(env: Env): Promise<Response> {
  const auth = await loadCfAuth(env);
  if (!auth) {
    return decorate(
      Response.json(
        { success: false, configured: false, error: "Cloudflare credentials not configured" },
        { status: 200 },
      ),
    );
  }
  try {
    // 1. Get accounts
    const accountsRes = await fetch(`${CF_API}/accounts?per_page=5`, {
      headers: auth,
    });
    const accountsJson = (await accountsRes.json()) as CfApiResponse<CfAccount[]>;
    if (!accountsJson.success || !accountsJson.result?.length) {
      return decorate(
        Response.json({
          success: false,
          configured: true,
          error: accountsJson.errors?.[0]?.message ?? "No Cloudflare accounts found",
        }, { status: 502 }),
      );
    }
    const accountId = accountsJson.result[0].id;

    // 2. Get workers.dev subdomain
    const subdomainRes = await fetch(
      `${CF_API}/accounts/${accountId}/workers/subdomain`,
      { headers: auth },
    );
    const subdomainJson = (await subdomainRes.json()) as CfApiResponse<{ subdomain: string }>;
    const subdomain = subdomainJson.result?.subdomain ?? "";

    // 3. List worker scripts
    const scriptsRes = await fetch(
      `${CF_API}/accounts/${accountId}/workers/scripts?per_page=50`,
      { headers: auth },
    );
    const scriptsJson = (await scriptsRes.json()) as CfApiResponse<CfWorkerScript[]>;
    if (!scriptsJson.success) {
      return decorate(
        Response.json({
          success: false,
          configured: true,
          error: scriptsJson.errors?.[0]?.message ?? "Could not list workers",
        }, { status: 502 }),
      );
    }

    const workers = (scriptsJson.result ?? []).map((w) => ({
      id: w.id,
      hostname: subdomain ? `${w.id}.${subdomain}.workers.dev` : w.id,
    }));

    return decorate(
      Response.json({ success: true, configured: true, data: workers, subdomain }),
    );
  } catch {
    return decorate(
      Response.json(
        { success: false, configured: true, error: "could not reach the Cloudflare API" },
        { status: 502 },
      ),
    );
  }
}

/** Persist an allocated proxy domain onto a target in the Durable Object, including CF record tracking for cleanup. */
function setProxyDomain(
  env: Env,
  id: number,
  proxyDomain: string,
  cfZoneId?: string,
  cfRecordId?: string,
  cfDomainBindingId?: string,
): Promise<Response> {
  const req = new Request("https://do/__proxy-domain", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ id, proxyDomain, cfZoneId, cfRecordId, cfDomainBindingId }),
  });
  req.headers.set("X-Rork-DO-Class", "ItemsStore");
  req.headers.set("X-Rork-DO-Id", STORE_ID);
  return fetchDO(env, req);
}

/** Get Zone details including the parent account ID and zone name. */
async function getZoneDetails(
  env: Env,
  auth: Record<string, string>,
  zoneId: string,
): Promise<{ zoneName: string; accountId: string } | null> {
  try {
    const res = await fetch(`${CF_API}/zones/${zoneId}`, {
      headers: auth,
    });
    if (!res.ok) return null;
    const json = (await res.json()) as CfApiResponse<{ id: string; name: string; account: { id: string } }>;
    if (json.success && json.result?.account?.id) {
      return {
        zoneName: json.result.name,
        accountId: json.result.account.id,
      };
    }
  } catch {}
  return null;
}

/** Resolve the Worker script service name given the gateway host URL. */
async function findWorkerService(
  env: Env,
  auth: Record<string, string>,
  accountId: string,
  gatewayHost: string,
): Promise<string | null> {
  try {
    const res = await fetch(`${CF_API}/accounts/${accountId}/workers/scripts?per_page=50`, {
      headers: auth,
    });
    if (res.ok) {
      const json = (await res.json()) as CfApiResponse<CfWorkerScript[]>;
      if (json.success && json.result) {
        const match = json.result.find((w) =>
          gatewayHost.toLowerCase() === w.id.toLowerCase() ||
          gatewayHost.toLowerCase().startsWith(`${w.id.toLowerCase()}.`),
        );
        if (match) return match.id;
      }
    }
  } catch {}
  return gatewayHost.split(".")[0] || null;
}

/**
 * Allocate a purchased Cloudflare domain to a proxy target. Creates a proxied
 * CNAME record in the chosen zone pointing at this gateway host, then records
 * the hostname on the target so the app can surface it. Body:
 * `{ proxyId, zoneId, hostname }`.
 */
async function allocateDomain(request: Request, env: Env): Promise<Response> {
  const auth = await loadCfAuth(env);
  if (!auth) {
    return decorate(
      Response.json(
        { success: false, configured: false, error: "Cloudflare credentials not configured" },
        { status: 400 },
      ),
    );
  }
  const body = (await request.json().catch(() => null)) as {
    proxyId?: number;
    zoneId?: string;
    hostname?: string;
  } | null;
  const proxyId = Number(body?.proxyId);
  const zoneId = (body?.zoneId ?? "").toString().trim();
  const hostname = (body?.hostname ?? "").toString().trim().toLowerCase();
  if (!proxyId || !zoneId || !hostname || !/^[a-z0-9.-]+\.[a-z]{2,}$/.test(hostname)) {
    return decorate(
      Response.json(
        { success: false, error: "proxyId, zoneId and a valid hostname are required" },
        { status: 400 },
      ),
    );
  }

  // Retrieve Zone details and Worker script service name to bind the Custom Domain trigger
  const zoneDetails = await getZoneDetails(env, auth, zoneId);
  if (!zoneDetails) {
    return decorate(
      Response.json(
        { success: false, error: "could not retrieve zone details from Cloudflare" },
        { status: 502 },
      ),
    );
  }
  const { zoneName, accountId } = zoneDetails;

  const configuredHost = (await readConfigFromDO(env, "cf."))["cf.gateway_host"] ?? "";
  const gatewayHost = configuredHost || new URL(request.url).host;

  const serviceName = await findWorkerService(env, auth, accountId, gatewayHost);
  if (!serviceName) {
    return decorate(
      Response.json(
        { success: false, error: "could not resolve Cloudflare Worker script service name" },
        { status: 500 },
      ),
    );
  }

  try {
    // 1. Lookup and delete any conflicting DNS records for this hostname
    const existingDnsRes = await fetch(
      `${CF_API}/zones/${zoneId}/dns_records?name=${hostname}`,
      { headers: auth },
    );
    if (existingDnsRes.ok) {
      const existingDns = (await existingDnsRes.json()) as CfApiResponse<{ id: string }[]>;
      if (existingDns.success && existingDns.result) {
        for (const record of existingDns.result) {
          await fetch(`${CF_API}/zones/${zoneId}/dns_records/${record.id}`, {
            method: "DELETE",
            headers: auth,
          }).catch(() => null);
        }
      }
    }

    // 2. Bind the Custom Domain trigger to the Worker service
    // This will automatically create the correct managed CNAME record in the zone.
    const domainRes = await fetch(`${CF_API}/accounts/${accountId}/workers/domains`, {
      method: "PUT",
      headers: { ...auth, "Content-Type": "application/json" },
      body: JSON.stringify({
        zone_id: zoneId,
        zone_name: zoneName,
        hostname: hostname,
        service: serviceName,
        environment: "production",
      }),
    });
    const domainJson = (await domainRes.json()) as CfApiResponse<{ id: string }>;
    if (!domainJson.success) {
      const message = domainJson.errors?.[0]?.message ?? "could not bind custom domain to worker";
      return decorate(
        Response.json({ success: false, error: message }, { status: 502 }),
      );
    }

    const cfDomainBindingId = domainJson.result?.id ?? "";

    // 3. Lookup the newly auto-created CNAME DNS record to store its ID
    let dnsRecordId = "";
    try {
      const dnsQueryRes = await fetch(
        `${CF_API}/zones/${zoneId}/dns_records?name=${hostname}&type=CNAME`,
        { headers: auth },
      );
      if (dnsQueryRes.ok) {
        const dnsQueryJson = (await dnsQueryRes.json()) as CfApiResponse<{ id: string }[]>;
        if (dnsQueryJson.success && dnsQueryJson.result?.length) {
          dnsRecordId = dnsQueryJson.result[0].id;
        }
      }
    } catch {}

    // 4. Save to Durable Object
    const stored = await setProxyDomain(
      env,
      proxyId,
      hostname,
      zoneId,
      dnsRecordId,
      cfDomainBindingId,
    );
    const storedJson = (await stored.json().catch(() => null)) as {
      data?: unknown;
    } | null;
    return decorate(
      Response.json({
        success: true,
        data: {
          hostname,
          target: gatewayHost,
          record: { id: dnsRecordId, name: hostname },
          proxy: storedJson?.data ?? null,
        },
      }),
    );
  } catch {
    return decorate(
      Response.json(
        { success: false, error: "could not reach the Cloudflare API" },
        { status: 502 },
      ),
    );
  }
}

const RATE_LIMIT_REQUESTS = 100;
const RATE_LIMIT_WINDOW = 60; // seconds
const CACHE_TTL = 10; // seconds
const GATEWAY_VERSION = "1.0.0";
const INTERCEPT_BODY_MAX_BYTES = 16_384; // Cap per-body read for intercept captures.

// Hop-by-hop headers must never be forwarded between client <-> origin.
const HOP_BY_HOP = new Set([
  "connection",
  "keep-alive",
  "proxy-authenticate",
  "proxy-authorization",
  "te",
  "trailer",
  "transfer-encoding",
  "upgrade",
]);

const CORS: Record<string, string> = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Methods": "GET, POST, PUT, DELETE, OPTIONS",
  "Access-Control-Allow-Headers": "Content-Type, Authorization",
  "Access-Control-Expose-Headers":
    "X-Cache, X-RateLimit-Limit, X-RateLimit-Remaining, X-RateLimit-Reset, X-Edge-Latency, Retry-After",
};

const SECURITY: Record<string, string> = {
  "X-Content-Type-Options": "nosniff",
  "X-Frame-Options": "DENY",
  "Referrer-Policy": "strict-origin-when-cross-origin",
  "Permissions-Policy": "geolocation=(), microphone=(), camera=()",
};

const STORE_ID = "global";

function dispatch(request: Request, env: Env): Promise<Response> {
  const wrapped = new Request(request.url, request);
  wrapped.headers.set("X-Rork-DO-Class", "ItemsStore");
  wrapped.headers.set("X-Rork-DO-Id", STORE_ID);
  return fetchDO(env, wrapped);
}

type TrafficLog = {
  ts: number;
  method: string;
  path: string;
  status: number;
  latencyMs: number;
  cache: string;
  ip: string;
  country: string;
  colo: string;
  proxy: string;
};

type ProxyConfig = {
  id: number;
  slug: string;
  name: string;
  targetUrl: string;
  enabled: boolean;
  interceptEnabled: boolean;
};

/** Look up a proxy from the DO by its numeric id (internal). */
async function resolveProxyById(
  env: Env,
  id: number,
): Promise<ProxyConfig & { proxyDomain?: string; cfZoneId?: string; cfRecordId?: string; cfDomainBindingId?: string } | null> {
  const req = new Request(`https://do/__proxy-by-id?id=${id}`);
  req.headers.set("X-Rork-DO-Class", "ItemsStore");
  req.headers.set("X-Rork-DO-Id", STORE_ID);
  const res = await fetchDO(env, req);
  if (!res.ok) return null;
  const json = (await res.json()) as {
    data?: ProxyConfig & { proxyDomain?: string; cfZoneId?: string; cfRecordId?: string; cfDomainBindingId?: string };
  };
  return json.data ?? null;
}

/**
 * Delete a Cloudflare DNS record by zone and record id. Best-effort —
 * failures are logged but never thrown, so a delete always proceeds.
 */
/**
 * Clean up Cloudflare resources (DNS record and Worker custom domain trigger) associated with a proxy.
 */
async function cleanupCloudflareResources(
  env: Env,
  zoneId: string,
  recordId: string,
  domainBindingId?: string,
): Promise<void> {
  const auth = await loadCfAuth(env);
  if (!auth) return;

  // 1. Delete CNAME record from Cloudflare
  if (zoneId && recordId) {
    try {
      await fetch(`${CF_API}/zones/${zoneId}/dns_records/${recordId}`, {
        method: "DELETE",
        headers: auth,
      });
    } catch {}
  }

  // 2. Delete Worker Custom Domain trigger from Cloudflare account
  if (zoneId && domainBindingId) {
    try {
      const zoneDetails = await getZoneDetails(env, auth, zoneId);
      if (zoneDetails?.accountId) {
        await fetch(`${CF_API}/accounts/${zoneDetails.accountId}/workers/domains/${domainBindingId}`, {
          method: "DELETE",
          headers: auth,
        });
      }
    } catch {}
  }
}

/**
 * Auto-allocate a Cloudflare domain for a newly created proxy. Picks the
 * first active zone, creates a CNAME record, and binds the Worker custom domain trigger.
 * Runs inside ctx.waitUntil so the client gets the initial 201 immediately.
 */
async function autoAllocateDomain(
  env: Env,
  proxyId: number,
  slug: string,
  fallbackHost: string,
): Promise<void> {
  const auth = await loadCfAuth(env);
  if (!auth) return;
  const configuredHost = (await readConfigFromDO(env, "cf."))["cf.gateway_host"] ?? "";
  const gatewayHost = configuredHost || fallbackHost;
  const zonesRes = await fetch(`${CF_API}/zones?per_page=5&status=active`, {
    headers: auth,
  }).catch(() => null);
  if (!zonesRes?.ok) return;
  const zonesJson = (await zonesRes.json()) as CfApiResponse<CfZone[]>;
  const zone = zonesJson.result?.[0];
  if (!zone) return;
  const hostname = `${slug}.${zone.name}`;
  // 1. Lookup and delete any conflicting DNS records for this hostname
  try {
    const existingDnsRes = await fetch(
      `${CF_API}/zones/${zone.id}/dns_records?name=${hostname}`,
      { headers: auth }
    );
    if (existingDnsRes.ok) {
      const existingDns = await existingDnsRes.json() as CfApiResponse<{ id: string }[]>;
      if (existingDns.success && existingDns.result) {
        for (const record of existingDns.result) {
          await fetch(`${CF_API}/zones/${zone.id}/dns_records/${record.id}`, {
            method: "DELETE",
            headers: auth,
          }).catch(() => null);
        }
      }
    }
  } catch {}

  // 2. Bind the Custom Domain trigger to the Worker service
  let cfDomainBindingId = "";
  try {
    const zoneDetails = await getZoneDetails(env, auth, zone.id);
    if (zoneDetails) {
      const workerService = await findWorkerService(env, auth, zoneDetails.accountId, gatewayHost);
      if (workerService) {
        const domainRes = await fetch(`${CF_API}/accounts/${zoneDetails.accountId}/workers/domains`, {
          method: "PUT",
          headers: { ...auth, "Content-Type": "application/json" },
          body: JSON.stringify({
            zone_id: zone.id,
            zone_name: zoneDetails.zoneName,
            hostname,
            service: workerService,
            environment: "production",
          }),
        });
        if (domainRes.ok) {
          const domainJson = await domainRes.json() as CfApiResponse<{ id: string }>;
          if (domainJson.success && domainJson.result?.id) {
            cfDomainBindingId = domainJson.result.id;
          }
        }
      }
    }
  } catch {}

  // 3. Lookup the newly auto-created CNAME DNS record to store its ID
  let dnsRecordId = "";
  try {
    const dnsQueryRes = await fetch(
      `${CF_API}/zones/${zone.id}/dns_records?name=${hostname}&type=CNAME`,
      { headers: auth },
    );
    if (dnsQueryRes.ok) {
      const dnsQueryJson = (await dnsQueryRes.json()) as CfApiResponse<{ id: string }[]>;
      if (dnsQueryJson.success && dnsQueryJson.result?.length) {
        dnsRecordId = dnsQueryJson.result[0].id;
      }
    }
  } catch {}

  // 4. Save to Durable Object
  await setProxyDomain(env, proxyId, hostname, zone.id, dnsRecordId, cfDomainBindingId);
}

/** Resolve a configured proxy target by slug from the Durable Object. */
async function resolveProxy(env: Env, slug: string): Promise<ProxyConfig | null> {
  const req = new Request(`https://do/__proxy?slug=${encodeURIComponent(slug)}`);
  req.headers.set("X-Rork-DO-Class", "ItemsStore");
  req.headers.set("X-Rork-DO-Id", STORE_ID);
  const res = await fetchDO(env, req);
  if (!res.ok) return null;
  const json = (await res.json()) as { data?: ProxyConfig };
  return json.data ?? null;
}

/** Resolve a configured proxy target by custom domain from the Durable Object. */
async function resolveProxyByDomain(env: Env, domain: string): Promise<ProxyConfig | null> {
  const req = new Request(`https://do/__proxy?domain=${encodeURIComponent(domain)}`);
  req.headers.set("X-Rork-DO-Class", "ItemsStore");
  req.headers.set("X-Rork-DO-Id", STORE_ID);
  const res = await fetchDO(env, req);
  if (!res.ok) return null;
  const json = (await res.json()) as { data?: ProxyConfig };
  return json.data ?? null;
}

/** Fire-and-forget bump of a proxy target's hit counter. */
function bumpProxyHits(env: Env, slug: string): Promise<void> {
  const req = new Request("https://do/__proxy-hit", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ slug }),
  });
  req.headers.set("X-Rork-DO-Class", "ItemsStore");
  req.headers.set("X-Rork-DO-Id", STORE_ID);
  return fetchDO(env, req).then(() => undefined);
}

/**
 * Traffic analyser interceptor. Fire-and-forget write of a single request's
 * metadata into the ItemsStore ring buffer. Runs via ctx.waitUntil so it never
 * blocks the client response.
 */
function logTraffic(request: Request, env: Env, entry: TrafficLog): Promise<void> {
  const log = new Request("https://do/__traffic", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(entry),
  });
  log.headers.set("X-Rork-DO-Class", "ItemsStore");
  log.headers.set("X-Rork-DO-Id", STORE_ID);
  return fetchDO(env, log).then(() => undefined);
}

/**
 * Intercept capture — fire-and-forget write of a proxied request/response
 * payload pair into durable storage. Only called when lab mode is on and the
 * resolved proxy has intercept enabled.
 */
function logIntercept(
  env: Env,
  entry: {
    ts: number;
    slug: string;
    method: string;
    path: string;
    reqHeaders: string;
    reqBody: string;
    respStatus: number;
    respHeaders: string;
    respBody: string;
    host: string;
  },
): Promise<void> {
  const ic = new Request("https://do/__intercept", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(entry),
  });
  ic.headers.set("X-Rork-DO-Class", "ItemsStore");
  ic.headers.set("X-Rork-DO-Id", STORE_ID);
  return fetchDO(env, ic).then(() => undefined);
}

function buildTrafficEntry(
  request: Request,
  response: Response,
  path: string,
  latencyMs: number,
  ip: string,
  proxy: string = "",
): TrafficLog {
  const cf = (request as Request & { cf?: { country?: string; colo?: string } }).cf;
  return {
    ts: Date.now(),
    method: request.method,
    path,
    status: response.status,
    latencyMs,
    cache: response.headers.get("X-Cache") ?? "",
    ip,
    country: cf?.country ?? request.headers.get("CF-IPCountry") ?? "",
    colo: cf?.colo ?? "",
    proxy,
  };
}

function decorate(response: Response, extra?: Record<string, string>): Response {
  const headers = new Headers(response.headers);
  for (const [k, v] of Object.entries({ ...CORS, ...SECURITY, ...(extra ?? {}) })) {
    headers.set(k, v);
  }
  return new Response(response.body, {
    status: response.status,
    statusText: response.statusText,
    headers,
  });
}

const isCacheable = (path: string, method: string): boolean =>
  method === "GET" && (path === "/api/items" || /^\/api\/items\/\d+$/.test(path));

/**
 * Reverse-proxy a request to a target origin through this Worker (the
 * self-hosted proxy domain). Everything under `/proxy/*` is forwarded.
 *
 * The upstream origin is resolved in priority order:
 *   1. `?target=https://host` query param (per-request override), or
 *   2. the `PROXY_TARGET` Worker env var (default upstream).
 *
 * The path after `/proxy` plus the original query string is appended to the
 * target. Hop-by-hop headers are stripped and standard `X-Forwarded-*` /
 * `X-Gateway-Version` headers are added so the origin sees the real client.
 */
async function reverseProxy(
  request: Request,
  env: Env,
): Promise<{ response: Response; proxy: string }> {
  const incoming = new URL(request.url);
  const host = incoming.hostname.toLowerCase();
  
  let segments = incoming.pathname
    .replace(/^\/proxy\/?/, "")
    .split("/")
    .filter(Boolean);

  const override = incoming.searchParams.get("target");
  let targetBase: string | undefined;
  let rest: string = segments.join("/");
  let proxyLabel = "";

  // 1. Try to resolve proxy by incoming host matching a custom domain.
  // We query by host. If not matched directly, we check if the host ends with an allocated domain (subdomain routing).
  let resolvedProxy: ProxyConfig & { proxyDomain?: string } | null = null;
  let subdomainPrefix = "";

  // We fetch a list of proxies or search by domain.
  // Let's search by domain. Since a user request can be for sub.domain.com, we can check matching domains.
  // We can query the DO by domain matching. To do this efficiently, we query the DO for the exact host first.
  resolvedProxy = await resolveProxyByDomain(env, host);
  
  if (!resolvedProxy) {
    // Check if the incoming host is a subdomain of a registered proxy domain.
    // e.g. "sub.westpac.joe.casino" where "westpac.joe.casino" is the proxyDomain.
    // We can query the DO with a suffix check, but since we have a resolveProxy endpoint,
    // we can request all proxies or do a smart suffix resolution.
    // Let's implement suffix matching. We can fetch all proxies or query DO.
    // Let's add a list / query to DO to find if any proxyDomain is a suffix of 'host'.
    // Or we can query DO for a domain suffix check. Let's make a query endpoint.
    // Actually, we can check if there's any matching proxy by testing suffixes of 'host'.
    // e.g. for "westpac.joe.casino", the host is "westpac.joe.casino".
    // If a request comes in for "api.westpac.joe.casino", we split the domain into parts:
    // ["api", "westpac", "joe", "casino"] -> check "westpac.joe.casino", then "joe.casino", etc.
    const hostParts = host.split(".");
    for (let i = 1; i < hostParts.length - 1; i++) {
      const parentDomain = hostParts.slice(i).join(".");
      const candidate = await resolveProxyByDomain(env, parentDomain);
      if (candidate) {
        resolvedProxy = candidate;
        subdomainPrefix = hostParts.slice(0, i).join(".");
        break;
      }
    }
  }

  if (override) {
    // Legacy/ad-hoc override: /proxy/<rest>?target=https://host
    targetBase = override;
    rest = segments.join("/");
  } else if (resolvedProxy) {
    if (!resolvedProxy.enabled) {
      return {
        proxy: resolvedProxy.slug,
        response: decorate(
          Response.json(
            { success: false, error: `proxy "${resolvedProxy.slug}" is disabled` },
            { status: 503 },
          ),
        ),
      };
    }
    targetBase = resolvedProxy.targetUrl;
    proxyLabel = resolvedProxy.slug;
    
    // For custom domains, pathname is the target pathname, not starting with /proxy/<slug>.
    // But if we detected a subdomainPrefix (e.g. "api" on "api.westpac.joe.casino"),
    // we want to prepend that subdomain to the request path or handle it.
    // The requirement says: "auto detect and proxy subdomains and extentions for all target websites dynamically".
    // This means if a user visits e.g. "api.westpac.joe.casino/v1/users", and the target is "https://westpac-api-origin.com",
    // we should proxy it dynamically.
    // Specifically, if a subdomain prefix is present, we prepend it as a path segment (or host subdomain) to the target URL.
    // Standard behavior: if subdomainPrefix exists (e.g. "api"), we can map it to target.
    // For example, if target is "https://westpac.com" and domain is "westpac.joe.casino",
    // visiting "api.westpac.joe.casino" -> target becomes "https://api.westpac.com".
    // Let's implement that: prepend the subdomainPrefix to the target host!
    // Or if the target host doesn't support subdomains, we can just proxy.
    // Let's modify the target URL host if subdomainPrefix is present:
    // e.g. new URL("https://westpac.com") -> "https://api.westpac.com".
    if (subdomainPrefix) {
      try {
        const parsedTarget = new URL(targetBase);
        parsedTarget.hostname = `${subdomainPrefix}.${parsedTarget.hostname}`;
        targetBase = parsedTarget.toString();
      } catch {}
    }
    
    rest = incoming.pathname; // Preserve full pathname for custom domain routing.
  } else if (segments.length > 0 && segments[0] !== "api") {
    // Configured target: /proxy/<slug>/<rest>
    const slug = segments[0];
    const config = await resolveProxy(env, slug);
    if (!config) {
      return {
        proxy: slug,
        response: decorate(
          Response.json(
            { success: false, error: `no proxy configured for "${slug}"` },
            { status: 404 },
          ),
        ),
      };
    }
    if (!config.enabled) {
      return {
        proxy: slug,
        response: decorate(
          Response.json(
            { success: false, error: `proxy "${slug}" is disabled` },
            { status: 503 },
          ),
        ),
      };
    }
    targetBase = config.targetUrl;
    rest = segments.slice(1).join("/");
    proxyLabel = config.slug;
  } else {
    targetBase = env.PROXY_TARGET;
    rest = "";
  }

  if (!targetBase) {
    return {
      proxy: proxyLabel,
      response: decorate(
        Response.json(
          {
            success: false,
            error:
              "no proxy target — add one in the app, or pass ?target=https://host",
          },
          { status: 502 },
        ),
      ),
    };
  }

  let target: URL;
  try {
    target = new URL(targetBase);
  } catch {
    return {
      proxy: proxyLabel,
      response: decorate(
        Response.json(
          { success: false, error: "invalid proxy target url" },
          { status: 400 },
        ),
      ),
    };
  }

  // Map remaining path onto the target origin, preserving query (minus ?target).
  const basePath = target.pathname.replace(/\/$/, "");
  target.pathname = `${basePath}/${rest}`.replace(/\/{2,}/g, "/");
  incoming.searchParams.delete("target");
  target.search = incoming.searchParams.toString();

  const headers = new Headers(request.headers);
  for (const name of HOP_BY_HOP) headers.delete(name);
  headers.set("Host", target.host);
  headers.set("X-Forwarded-Host", incoming.host);
  headers.set("X-Forwarded-Proto", incoming.protocol.replace(":", ""));
  headers.set(
    "X-Forwarded-For",
    request.headers.get("CF-Connecting-IP") ??
      request.headers.get("X-Forwarded-For") ??
      "anonymous",
  );
  headers.set("X-Gateway-Version", GATEWAY_VERSION);

  const upstream = new Request(target.toString(), {
    method: request.method,
    headers,
    body:
      request.method === "GET" || request.method === "HEAD"
        ? undefined
        : request.body,
    redirect: "manual",
  });

  try {
    const response = await fetch(upstream);
    const respHeaders = new Headers(response.headers);
    for (const name of HOP_BY_HOP) respHeaders.delete(name);
    respHeaders.set("X-Proxied-By", "edge-gateway-dashboard");
    if (proxyLabel) respHeaders.set("X-Proxy-Target", proxyLabel);

    // Intercept capture: only if lab mode is on AND this proxy has intercept
    // enabled. We read limited request/response bodies asynchronously so the
    // client response is never delayed.
    const labOn = env.INTERCEPT_LAB_MODE === "true";
    const interceptProxy = resolvedProxy || (segments.length > 0
      ? await resolveProxy(env, segments[0])
      : null);
    const shouldIntercept = labOn && interceptProxy?.interceptEnabled;

    let interceptPromise: Promise<void> | undefined;
    if (shouldIntercept) {
      const incomingHeaders = new Headers(request.headers);
      for (const name of HOP_BY_HOP) incomingHeaders.delete(name);
      const reqBody = request.clone().text().then(
        (t) => t.slice(0, INTERCEPT_BODY_MAX_BYTES),
      ).catch(() => "");
      const respBody = response.clone().text().then(
        (t) => t.slice(0, INTERCEPT_BODY_MAX_BYTES),
      ).catch(() => "");
      interceptPromise = Promise.all([reqBody, respBody]).then(
        ([reqB, respB]) =>
          logIntercept(env, {
            ts: Date.now(),
            slug: proxyLabel,
            method: request.method,
            path: target.pathname + (target.search || ""),
            reqHeaders: JSON.stringify(Object.fromEntries(incomingHeaders.entries())),
            reqBody: reqB,
            respStatus: response.status,
            respHeaders: JSON.stringify(Object.fromEntries(respHeaders.entries())),
            respBody: respB,
            host: target.host,
          }),
      );
    }

    return {
      proxy: proxyLabel,
      response: decorate(
        new Response(response.body, {
          status: response.status,
          statusText: response.statusText,
          headers: respHeaders,
        }),
      ),
      interceptPromise,
    };
  } catch {
    return {
      proxy: proxyLabel,
      response: decorate(
        Response.json(
          { success: false, error: "bad gateway — upstream unreachable" },
          { status: 502 },
        ),
      ),
    };
  }
}

export default {
  async fetch(request: Request, env: Env, ctx: ExecutionContext): Promise<Response> {
    const url = new URL(request.url);
    const path = url.pathname;
    const method = request.method;
    const start = Date.now();

    if (method === "OPTIONS") {
      return new Response(null, { status: 204, headers: { ...CORS, ...SECURITY } });
    }

    if (path === "/" || path === "/ping") {
      return decorate(
        Response.json({
          ok: true,
          gateway: "edge-gateway-dashboard",
          timestamp: new Date().toISOString(),
        }),
      );
    }

    const clientIp =
      request.headers.get("CF-Connecting-IP") ??
      request.headers.get("X-Forwarded-For") ??
      "anonymous";

    const hostName = url.hostname.toLowerCase();
    const isLocalhost = hostName === "localhost" || hostName === "127.0.0.1";
    let isCustomDomainRequest = false;

    if (!isLocalhost) {
      const resolvedCustomProxy = await resolveProxyByDomain(env, hostName);
      if (resolvedCustomProxy) {
        isCustomDomainRequest = true;
      } else {
        const hostParts = hostName.split(".");
        for (let i = 1; i < hostParts.length - 1; i++) {
          const parentDomain = hostParts.slice(i).join(".");
          const candidate = await resolveProxyByDomain(env, parentDomain);
          if (candidate) {
            isCustomDomainRequest = true;
            break;
          }
        }
      }
    }

    if (path === "/proxy" || path.startsWith("/proxy/") || isCustomDomainRequest) {
      const { response: proxied, proxy, interceptPromise } = await reverseProxy(request, env);
      ctx.waitUntil(
        logTraffic(
          request,
          env,
          buildTrafficEntry(request, proxied, path, Date.now() - start, clientIp, proxy),
        ),
      );
      if (proxy) ctx.waitUntil(bumpProxyHits(env, proxy));
      if (interceptPromise) ctx.waitUntil(interceptPromise);
      return proxied;
    }

    if (path === "/api/cloudflare/zones" && method === "GET") {
      return await listZones(env);
    }
    if (path === "/api/cloudflare/allocate" && method === "POST") {
      return await allocateDomain(request, env);
    }
    if (path === "/api/cloudflare/workers" && method === "GET") {
      return await listWorkers(env);
    }

    // ── Config API ─────────────────────────────────────────────────────
    // GET  /api/config         → read all cf.* config (masked values)
    // PUT  /api/config         → upsert cf.* config entries
    // POST /api/config/verify  → verify the saved credentials work
    if (path === "/api/config" && method === "GET") {
      const config = await readConfigFromDO(env, "cf.");
      // Mask sensitive values — show first 2 + last 2 chars (skip non-secrets)
      const NON_SECRET_KEYS = new Set(["cf.gateway_host"]);
      const masked: Record<string, string> = {};
      for (const [k, v] of Object.entries(config)) {
        if (NON_SECRET_KEYS.has(k)) {
          masked[k] = v;
        } else {
          masked[k] = v.length > 6
            ? `${v.slice(0, 2)}${"*".repeat(Math.min(v.length - 4, 12))}${v.slice(-2)}`
            : v ? "***" : "";
        }
      }
      // Include whether env vars are configured (they take priority)
      const envConfigured = !!cfAuthHeaders(env);
      return decorate(
        Response.json({
          success: true,
          data: masked,
          envConfigured,
          hasStoredConfig: Object.keys(config).some(
            (k) => config[k] && config[k].length > 0,
          ),
        }),
      );
    }
    if (path === "/api/config" && method === "PUT") {
      const body = (await request.json().catch(() => null)) as Record<
        string,
        string | null
      > | null;
      if (!body || typeof body !== "object") {
        return decorate(
          Response.json(
            { success: false, error: "invalid body" },
            { status: 400 },
          ),
        );
      }
      // Only allow cf.* keys from the frontend
      const allowed = ["cf.api_token", "cf.api_key", "cf.api_email", "cf.gateway_host"];
      const filtered: Record<string, string | null> = {};
      for (const key of allowed) {
        if (key in body) {
          filtered[key] = body[key];
        }
      }
      await writeConfigToDO(env, filtered);
      return decorate(Response.json({ success: true }));
    }
    if (path === "/api/config/verify" && method === "POST") {
      const auth = await loadCfAuth(env);
      if (!auth) {
        return decorate(
          Response.json({
            success: true,
            data: { valid: false, error: "No credentials configured" },
          }),
        );
      }
      try {
        const res = await fetch(`${CF_API}/user/tokens/verify`, {
          headers: auth,
        });
        const json = (await res.json()) as CfApiResponse<{ status: string }>;
        if (json.success && json.result?.status === "active") {
          return decorate(
            Response.json({
              success: true,
              data: { valid: true, status: "active" },
            }),
          );
        }
        // For Global API Key auth, try listing zones as verification
        if (!json.success) {
          const zonesRes = await fetch(`${CF_API}/zones?per_page=1`, {
            headers: auth,
          });
          const zonesJson = (await zonesRes.json()) as CfApiResponse<unknown>;
          if (zonesJson.success) {
            return decorate(
              Response.json({
                success: true,
                data: { valid: true, status: "active" },
              }),
            );
          }
        }
        return decorate(
          Response.json({
            success: true,
            data: {
              valid: false,
              error:
                json.errors?.[0]?.message ?? "Token verification failed",
            },
          }),
        );
      } catch {
        return decorate(
          Response.json({
            success: true,
            data: { valid: false, error: "Could not reach Cloudflare API" },
          }),
        );
      }
    }

    // Intercept DELETE on a proxy target so we can clean up the Cloudflare
    // DNS record before the row is removed from durable storage.
    const proxyDeleteMatch = path.match(/^\/api\/proxies\/(\d+)$/);
    if (proxyDeleteMatch && method === "DELETE") {
      const id = Number(proxyDeleteMatch[1]);
      const proxy = await resolveProxyById(env, id);
      if (proxy?.cfZoneId && (proxy.cfRecordId || proxy.cfDomainBindingId)) {
        ctx.waitUntil(cleanupCloudflareResources(env, proxy.cfZoneId, proxy.cfRecordId, proxy.cfDomainBindingId));
      }
      // Fall through to dispatch — DO handles the actual row deletion.
    }

    // Intercept POST /api/proxies so we can auto-allocate a Cloudflare
    // domain after the DO creates the record.
    const isProxyCreate = path === "/api/proxies" && method === "POST";

    const host = url.hostname.toLowerCase();
    let isCustomDomain = false;
    const resolvedCustomProxy = await resolveProxyByDomain(env, host);
    if (resolvedCustomProxy) {
      isCustomDomain = true;
    } else {
      const hostParts = host.split(".");
      for (let i = 1; i < hostParts.length - 1; i++) {
        const parentDomain = hostParts.slice(i).join(".");
        const candidate = await resolveProxyByDomain(env, parentDomain);
        if (candidate) {
          isCustomDomain = true;
          break;
        }
      }
    }

    const isTraffic = path === "/api/traffic";
    const isIntercepts = path === "/api/intercepts";
    const isProxyConfig = path === "/api/proxies" || /^\/api\/proxies\/\d+$/.test(path);
    const isConfigRoute = path.startsWith("/api/config");
    if (
      path !== "/health" &&
      !path.startsWith("/api/items") &&
      !isTraffic &&
      !isIntercepts &&
      !isProxyConfig &&
      !isConfigRoute &&
      !isCustomDomain
    ) {
      return decorate(
        Response.json({ success: false, error: "not found" }, { status: 404 }),
      );
    }

    // Per-IP rate limit + edge cache both live in the DO (single resident
    // instance), so HIT/MISS and rate budgets are consistent. Pass config forward.
    const originReq = new Request(request.url, request);
    originReq.headers.set("X-Client-IP", clientIp);
    originReq.headers.set("X-Rate-Limit", String(RATE_LIMIT_REQUESTS));
    originReq.headers.set("X-Rate-Window", String(RATE_LIMIT_WINDOW));
    originReq.headers.set("X-Cache-TTL", String(CACHE_TTL));

    const response = await dispatch(originReq, env);
    const latency = `${Date.now() - start}ms`;

    const extra: Record<string, string> = { "X-Edge-Latency": latency };
    if (!response.headers.has("X-Cache")) {
      extra["X-Cache"] = "BYPASS";
    }
    const decorated = decorate(response, extra);

    // Auto-allocate a Cloudflare domain when a new proxy is created, so the
    // user doesn't have to manually pick a zone — the gateway handles it.
    if (isProxyCreate && decorated.ok) {
      const cloned = decorated.clone();
      ctx.waitUntil(
        cloned
          .json()
          .then((json: { data?: { id: number; slug: string } }) => {
            const proxy = json?.data;
            if (proxy?.id && proxy?.slug) {
              return autoAllocateDomain(env, proxy.id, proxy.slug, url.host);
            }
          })
          .catch(() => undefined),
      );
    }

    // Intercept everything except reads of the analyser feed and proxy config
    // management, so the traffic view doesn't fill up with its own polling.
    if (!isTraffic && !isProxyConfig) {
      ctx.waitUntil(
        logTraffic(
          request,
          env,
          buildTrafficEntry(request, decorated, path, Date.now() - start, clientIp),
        ),
      );
    }
    return decorated;
  },
} satisfies ExportedHandler<Env>;
